const d = new Date();
msg.payload = d.toLocaleString('ko-KR', { hour12: false });
return msg;

const raw = (msg.payload ?? '').toString();
const m = raw.match(/S:\s*([^|]+)/);
const s = m ? m[1].trim().replace(/\s+/g, ' ') : '-';
return [[{ payload: raw }], [{ payload: s }]];

const s = (msg.payload || '').toString();
const parts = s.split('|').map(x => x.trim());
const w = parts.find(x => x.startsWith('W:'));
let ssid = '-';
let ip = '-';
if (w) {
  const rest = w.slice(2).trim();
  const k = rest.lastIndexOf(' ip=');
  if (k >= 0 && rest.startsWith('ssid=')) {
    ssid = rest.slice(5, k).trim();
    ip = rest.slice(k + 4).trim();
    if (!ssid) ssid = '-';
    if (!ip) ip = '-';
    if (ip === '0.0.0.0') ip = '-';
  }
}
return [[{ payload: ssid }], [{ payload: ip }]];

const chKeys = ['led_a1','led_a2','pump_a1','pump_a2','led_b1','pump_b1','pump_b2'];
const labels = { led_a1:'LED A1', led_a2:'LED A2', pump_a1:'PUMP A1', pump_a2:'PUMP A2', led_b1:'LED B1', pump_b1:'PUMP B1', pump_b2:'PUMP B2' };
const rows = chKeys.map(k => {
  const st = flow.get(k);
  const au = flow.get('auto_'+k);
  const ons = flow.get('on_'+k);
  const offs = flow.get('off_'+k);
  return {
    key: k,
    label: labels[k] || k,
    on: st === 1 || st === true || st === '1',
    auto: au === 1 || au === true || au === '1',
    onSec: (typeof ons === 'number' && !Number.isNaN(ons)) ? ons : null,
    offSec: (typeof offs === 'number' && !Number.isNaN(offs)) ? offs : null
  };
});
msg.payload = rows;
msg.deviceId = flow.get('deviceId') || 'cronusfarm-01';
const lt = (flow.get('lastTeleStr') || '').toString();
msg.lastTele = lt;
msg.teleShort = lt.length > 140 ? lt.slice(0, 140) + '…' : lt;
msg.stats = {
  onCh: rows.filter(r => r.on).length,
  autoCh: rows.filter(r => r.auto).length,
  total: rows.length
};
return msg;

const s=(msg.payload||'').toString().trim();
msg.payload = (s.split(/\s+/)[0]||'-');
return msg;

const s=(msg.payload||'').toString().trim();
msg._ok = (s==='active');
msg.payload = msg._ok ? 'online' : 'offline';
return msg;

const s=(msg.payload||'').toString().trim();
msg._ok = (s==='active');
msg.payload = msg._ok ? 'online' : 'offline';
return msg;

flow.set('arduinoLastTeleMs', Date.now());
flow.set('lastTeleStr', (msg.payload || '').toString());
return msg;

const now=Date.now();
const ls=flow.get('arduinoLastStatusMs')||0;
const lt=flow.get('arduinoLastTeleMs')||0;
const ok=((now-ls)<30000)||((now-lt)<5000);
msg._ok=ok;
msg.payload=ok?'정상':'미수신';
msg.statusAge=ls?Math.floor((now-ls)/1000):null;
msg.teleAge=lt?Math.floor((now-lt)/1000):null;
const raw=(flow.get('lastTeleStr')||'').toString();
msg.telePreview = raw.length>200 ? raw.slice(0,200)+'…' : raw;
return msg;

const ok = !!msg._ok;
msg.payload = ok ? 'online' : 'offline';
msg.color = ok ? 'lime' : 'grey';
return msg;

// tele 예)
// S:실제 출력 | AUTO:auto_*=1(자동)/0(수동) … 구형 펌웨어는 "A:led_a1=0"처럼 채널키=자동여부
//
// 중요: tele이 1초마다 오기 때문에, UI 드롭다운(dd_*)을 매번 덮어쓰면 "시간이 계속 바뀌는" 것처럼 보일 수 있습니다.
// 여기서는 on_/off_ 초 값만 반영하고(dd_ 분/초 UI 갱신은 하지 않음), 드롭다운은 사용자가 바꾼 값이 유지되도록 합니다.

const s=(msg.payload||'').toString();
function parseKV(part){
  const out={};
  (part||'').trim().split(/\s+/).forEach(tok=>{
    const m=tok.match(/^([^=]+)=(.+)$/);
    if(!m) return;
    out[m[1]] = m[2];
  });
  return out;
}

const ps = s.split('|').map(x=>x.trim());
const pS = ps.find(x=>x.startsWith('S:'));
const pA = ps.find(x=>x.startsWith('AUTO:')) || ps.find(x=>x.startsWith('A:'));
const pT = ps.find(x=>x.startsWith('T:'));

const kvS = parseKV(pS ? pS.slice(2) : '');
const kvA = parseKV(pA ? (pA.startsWith('AUTO:') ? pA.slice(5) : pA.slice(2)) : '');
const kvT = parseKV(pT ? pT.slice(2) : '');

const chKeys = ['led_a1','led_a2','pump_a1','pump_a2','led_b1','pump_b1','pump_b2'];

const out=[];
chKeys.forEach(k=>{
  if(k in kvS) {
    const v = (kvS[k]==='1')?1:0;
    flow.set(k, v);
    out.push({topic:k, payload: v});
  }
});
chKeys.forEach(k=>{
  const ak = 'auto_'+k;
  let raw = kvA[ak];
  if (raw === undefined) raw = kvA[k];
  if (raw === undefined) return;
  const v = (raw==='1')?1:0;
  flow.set(ak, v);
  out.push({topic:ak, payload: v});
});

Object.keys(kvT).forEach(k=>{
  // pump_x=30/90
  const m = (kvT[k]||'').match(/^(\d+)\/(\d+)$/);
  if(!m) return;
  const onV = parseInt(m[1],10);
  const offV = parseInt(m[2],10);
  const onK = 'on_'+k;
  const offK = 'off_'+k;
  flow.set(onK, onV);
  flow.set(offK, offV);
  out.push({topic:onK, payload: onV});
  out.push({topic:offK, payload: offV});
});

return [out];

const devId = flow.get('deviceId') || 'cronusfarm-01';
flow.set('deviceId', devId);

const k = (msg.topic||'').toString().trim();
if(!k) return null;
const v = (msg.payload===1 || msg.payload===true || msg.payload==='1' || msg.payload==='on') ? 1 : 0;

// 스위치 조작 시: 해당 채널을 수동(auto=0)으로 고정하고, 즉시 ON/OFF 값을 cmd로 발행
// - 반드시 2회 발행(auto -> state). Function 노드 출력 1개에서 여러 메시지를 내보내려면
//   [[msg1, msg2]] 형태(출력 포트별 메시지 배열)로 반환해야 합니다.
const t = `cronusfarm/${devId}/cmd`;
const m1 = {topic:t, payload:`auto_${k}=0`};
const m2 = {topic:t, payload:`${k}=${v}`};
return [[m1, m2]];

const key = (msg.topic || '').toString();
const v = Number(msg.payload);
if (!key) return null;
flow.set(key, isNaN(v) ? 0 : v);
const mm = key.match(/^dd_(on|off)_(pump_[a-z0-9]+)_(m|s)$/);
if (!mm) return null;
const kind = mm[1];
const pk = mm[2];
const minutes = Number(flow.get('dd_' + kind + '_' + pk + '_m')) || 0;
const seconds = Number(flow.get('dd_' + kind + '_' + pk + '_s')) || 0;
let t = minutes * 60 + seconds;
if (t < 1) t = 1;
if (t > 3600) t = 3600;
const outTopic = kind + '_' + pk;
flow.set(outTopic, t);
msg.topic = outTopic;
msg.payload = t;
return msg;

const devId = flow.get('deviceId') || 'cronusfarm-01';
flow.set('deviceId', devId);

const key = (msg.topic||'').toString();
const val = msg.payload;
if (key) flow.set(key, val);

const keys = [
  'led_a1','led_a2','pump_a1','pump_a2','led_b1','pump_b1','pump_b2',
  'auto_led_a1','auto_led_a2','auto_pump_a1','auto_pump_a2','auto_led_b1','auto_pump_b1','auto_pump_b2',
  'on_pump_a1','off_pump_a1','on_pump_a2','off_pump_a2','on_pump_b1','off_pump_b1','on_pump_b2','off_pump_b2'
];

const parts=[];
keys.forEach(k=>{
  const v = flow.get(k);
  if (v === undefined || v === null) return;
  parts.push(`${k}=${v}`);
});

msg.topic = `cronusfarm/${devId}/cmd`;
msg.payload = parts.join(' ');
return msg;

const devId = flow.get('deviceId') || 'cronusfarm-01';
flow.set('deviceId', devId);

// FlexDash 위젯마다 topic이 다르게 들어올 수 있어 방어적으로 처리
const candidates = [
  msg.topic,
  msg.fd_output_topic,
  msg.fdOutputTopic,
  msg?._fd?.output_topic,
  msg?._fd?.outputTopic,
  msg?.widget?.topic
];
const k = (candidates.find(x => (x ?? '').toString().trim().length > 0) ?? '').toString().trim();
if(!k) return null;

// FlexDash toggle payload는 기본 true/false 또는 1/0
const v = (msg.payload===1 || msg.payload===true || msg.payload==='1' || msg.payload==='on') ? 1 : 0;

const t = `cronusfarm/${devId}/cmd`;
const m1 = {topic:t, payload:`auto_${k}=0`};
const m2 = {topic:t, payload:`${k}=${v}`};
return [[m1, m2]];

const sensors = [
  { key: 'temp', unit: '°C' },
  { key: 'hum', unit: '%' },
  { key: 'ec', unit: 'mS/cm' },
  { key: 'ph', unit: 'pH' },
];

const actKeys = ['led_a1','led_a2','led_b1','pump_a1','pump_a2','pump_b1','pump_b2'];

const out = [];
for (const s of sensors) {
  out.push({
    _demo: { kind: 'sensor', key: s.key, unit: s.unit },
    query: `SELECT mean("value") AS value FROM "sensor" WHERE ("key"='${s.key}') AND time > now() - 30d GROUP BY time(1h) fill(null)`
  });
}

out.push({
  _demo: { kind: 'act', key: 'actuator' },
  query: `SELECT last("value") AS value FROM "actuator" WHERE ("key" =~ /^(led|pump)_/) AND time > now() - 30d GROUP BY time(1h), "key" fill(previous)`
});

return [out];

const meta = msg._demo || {};
const rows = msg.payload;

// influxdb in(rawOutput=true) 결과는 배열/객체가 섞일 수 있어 방어
const arr = Array.isArray(rows) ? rows : (rows ? [rows] : []);

function toSeries(points, label) {
  const out = [];
  for (const p of points) {
    const t = p.time || p.timestamp || p._time;
    const v = (p.value ?? p.mean ?? p.last ?? p.value_float ?? null);
    const ts = t ? new Date(t).getTime() : Date.now();
    if (v === null || v === undefined) continue;
    out.push({ x: ts, y: Number(v) });
  }
  return { series: [{ name: label, data: out }] };
}

// 센서(단일 키) 쿼리
if (meta.kind === 'sensor') {
  const label = `${meta.key}${meta.unit ? ' ('+meta.unit+')' : ''}`;
  msg.payload = toSeries(arr, label).series;
  msg.topic = `demo/sensor/${meta.key}`;
  return msg;
}

// actuator(키별로 섞여 올 수 있음): key별로 분리
if (meta.kind === 'act') {
  const byKey = new Map();
  for (const p of arr) {
    const k = p.key || (p.tags && p.tags.key) || p.tag_key || 'unknown';
    if (!byKey.has(k)) byKey.set(k, []);
    byKey.get(k).push(p);
  }
  const series = [];
  for (const [k, pts] of byKey.entries()) {
    const s = toSeries(pts, k).series[0];
    series.push(s);
  }
  msg.payload = series;
  msg.topic = `demo/actuator`;
  return msg;
}

return null;

msg.headers = msg.headers || {};
msg.headers['Content-Type'] = 'text/html; charset=utf-8';
return msg;

function pick(min, max, digits=1) {
  const v = min + (max-min) * Math.random();
  const p = Math.pow(10, digits);
  return Math.round(v*p)/p;
}

msg.payload = {
  ts: new Date().toISOString(),
  demo: true,
  sensors: {
    temp: pick(20, 28, 1),
    hum: pick(45, 80, 1),
    ec: pick(0.8, 2.4, 2),
    ph: pick(5.5, 6.7, 2)
  },
  actuators: {
    led_a1: Math.random() > 0.5 ? 1 : 0,
    led_a2: Math.random() > 0.5 ? 1 : 0,
    led_b1: Math.random() > 0.5 ? 1 : 0,
    pump_a1: Math.random() > 0.7 ? 1 : 0,
    pump_a2: Math.random() > 0.7 ? 1 : 0,
    pump_b1: Math.random() > 0.7 ? 1 : 0,
    pump_b2: Math.random() > 0.7 ? 1 : 0
  }
};
msg.headers = { 'Content-Type': 'application/json; charset=utf-8' };
return msg;
